def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-10
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) * np.exp(-capacity / (item + epsilon))
            acc = 0.0
            for x in range(1, int(capacity) + 3):
                for y in range(1, int(item) + 2):
                    val = ((x * y) ** 0.5) / (x + y + epsilon)
                    if (x + y) % 4 == 0:
                        acc += np.tanh(val)
                    else:
                        acc -= np.tanh(val)
                if acc > 20:
                    break
            if capacity % 4 == 1:
                priority += np.sin(acc)
            else:
                priority -= np.cos(acc / (acc + epsilon))
            priority *= (1 + (capacity % 5) * 0.07)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log1p(capacity)
            modifier = 1.0
            for m in range(1, int(item) + 3):
                if m % 4 == 1:
                    priority += np.sqrt(m) / (capacity + 1) ** 0.5
                elif m % 4 == 2:
                    modifier *= np.sin(m / (item + epsilon))
                elif m % 4 == 3:
                    priority -= np.log(m + ratio)
                else:
                    priority += np.exp(-m / (capacity + 1))
            priority *= abs(np.cos(modifier))
            if priority < 0:
                priority = 0
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.sqrt(capacity + epsilon)
            acc = 0.0
            for n in range(1, int(capacity) + 1):
                value = ((ratio + n / (capacity + 1)) ** 2) / (n + epsilon)
                if n % 2 == 0:
                    acc += np.log1p(value)
                else:
                    acc -= np.exp(-value)
                if abs(acc) > 10:
                    break
            priority += acc * 0.5
            if capacity % 3 == 0:
                priority *= 1.15
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * (capacity ** 0.3)
            factor = 1
            for p in range(1, 7):
                factor *= (ratio + p / (capacity + 1))
                if factor > 7:
                    factor = np.log(factor + 1)
                    break
            priority *= factor
            for q in range(1, 4):
                priority += ((-1) ** q) * np.sin(ratio * q * np.pi)
        elif 0.1 < ratio <= 0.5:
            total = 0
            for j in range(1, int(capacity) + 2):
                val = ((ratio ** j) * np.cos(j * ratio)) / (j + epsilon)
                if j % 3 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.75 * np.log(capacity + 1)
        else:
            base = 0.5
            acc = 0
            for j in range(1, int(capacity) + 3):
                term = ((item + epsilon) / (j + epsilon)) ** (0.5 * ratio)
                if j % 5 == 0:
                    acc += np.exp(-term)
                else:
                    acc -= np.log1p(term)
                if abs(acc) > 30:
                    break
            priority = base + abs(acc) * 0.3
            if capacity < item:
                priority *= 0.85
        if capacity < item:
            diff = (item - capacity)
            penalty = diff * 25
            cycle = 1
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty += np.sqrt(p + 1) * cycle
                    cycle *= -1
                else:
                    penalty -= p * 0.15
            penalty = max(penalty, 0)
            priority += penalty * 1.2
        if priority < 0:
            priority = 0.0
        priorities[i] = priority
    return priorities
